css:
/* Immersive Black Archive Styling - Open Research Library */
body {
    background: #0A0F1A;
    font-family: 'Inter', system-ui, -apple-system, 'Segoe UI', sans-serif;
}
.glass-panel {
    background: rgba(5, 10, 22, 0.75);
    backdrop-filter: blur(16px);
    border: 1px solid rgba(0, 255, 255, 0.15);
}
.neon-border {
    box-shadow: 0 0 8px rgba(0, 255, 255, 0.2), inset 0 0 2px rgba(0, 255, 255, 0.1);
}
/* Timeline rail */
.timeline-rail-vertical { position: relative; }
.timeline-rail-vertical::before {
    content: ''; position: absolute; left: 18px; top: 20px; bottom: 20px;
    width: 2px; background: linear-gradient(to bottom, #0ff, #0ff8, #0ff);
    opacity: 0.5; border-radius: 2px;
}
.timeline-row { transition: all 0.2s ease; cursor: pointer; }
.timeline-row:hover { background: rgba(0, 255, 255, 0.08); border-left-color: #0ff; transform: translateX(4px); }
.timeline-row.active { background: rgba(0, 255, 255, 0.12); border-left: 3px solid #0ff; }
.card-neon { transition: transform 0.2s, border-color 0.2s; }
.card-neon:hover { transform: translateY(-4px); border-color: #0ff; box-shadow: 0 12px 24px -12px #0ff3; }
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: #0a0f1a; }
::-webkit-scrollbar-thumb { background: #0ff5; border-radius: 5px; }
@media (max-width: 1023px) { .timeline-rail-vertical::before { left: 12px; } }
.line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
/* Hero image overlay */
.hero-image-overlay { background: linear-gradient(135deg, #020408 0%, rgba(2,4,8,0.5) 60%, rgba(0,0,0,0.3) 100%); }
/* Kardashev badge colors */
.k-type0 { background: #3b3b3b; } .k-type1 { background: #2e5a2e; } .k-type2 { background: #2e4a6e; }
.k-type3 { background: #5a2e6e; } .k-speculative { background: #6e5a2e; } .k-hypothetical { background: #3a4a5a; }
/* Source card styling */
.source-card { transition: all 0.2s ease; }
.source-card:hover { border-color: #0ff; transform: translateY(-2px); }

