        icon: "fas fa-landmark",
      },
      {
        id: "Archaeology",
        label: "Archaeology",
        icon: "fas fa-monument",
      },
      {
        id: "Mythology",
        label: "Mythology",
        icon: "fas fa-dragon",
      },
      // ============================================================
      // NON-HUMAN / UFO / PARANORMAL
      // ============================================================
      {
        id: "Non-Human Intelligence Claims",
        label: "NHI Claims",
        icon: "fas fa-user-astronaut",
      },
      {
        id: "UAP Cases",
        label: "UAP Cases",
        icon: "fas fa-ufo",
      },
      {
        id: "Witnesses",
        label: "Witnesses",
        icon: "fas fa-eye",
      },
      // ============================================================
      // RESEARCH & GOVERNMENT
      // ============================================================
      {
        id: "Researchers",
        label: "Researchers",
        icon: "fas fa-book-open-reader",
      },
      {
        id: "Intelligence & Government",
        label: "Intel & Government",
        icon: "fas fa-building-columns",
      },
      // ============================================================
      // SCIENCE & TECHNOLOGY
      // ============================================================
      {
        id: "Technologies",
        label: "Technologies",
        icon: "fas fa-microchip",
      },
      {
        id: "Scientific Concepts",
        label: "Scientific Concepts",
        icon: "fas fa-atom",
      },
      // ============================================================
      // KNOWLEDGE & SYSTEMS
      // ============================================================
      {
        id: "Sources",
        label: "Source Library",
        icon: "fas fa-book",
      },
      {
        id: "Economics",
        label: "Economics",
        icon: "fas fa-chart-line",
      },
      // ============================================================
      // USER PAGES
      // ============================================================
      {
        id: "Favorites",
        label: "Favorites",
        icon: "fas fa-star",
      },
      {
        id: "NotesPage",
        label: "Notes",
        icon: "fas fa-pen-to-square",
      },
    ],
    activeCategory: "Human Timeline",
    searchTerm: "",
    selectedRecord: null,
    favoritesIds: new Set(),
    notesStore: {},
    currentHumanEra: "All",
    toggleFavoritesOnly: false,
    notesSearch: "",
    detailsFieldsList: [
      {
        key: "aliases",
        label: "Aliases",
      },
      {
        key: "origin",
        label: "Origin",
      },
      {
        key: "appearance",
        label: "Appearance",
      },
      {
        key: "societalStructure",
        label: "Society / Structure",
      },
      {
        key: "governance",
        label: "Governance",
      },
      {
        key: "economy",
        label: "Economy",
      },
      {
        key: "technologyLevel",
        label: "Technology Level",
      },
      {
        key: "religionSpirituality",
        label: "Religion / Spirituality",
      },
      {
        key: "collapseTheory",
        label: "Collapse Theory",
      },
      {
        key: "associatedArtifacts",
        label: "Associated Artifacts",
      },
      {
        key: "controversyNotes",
        label: "Controversy Notes",
      },
      {
        key: "skepticismNotes",
        label: "Skepticism Notes",
      },
      {
        key: "modernRelevance",
        label: "Modern Relevance",
      },
    ],
    get filteredNotes() {
      let f = {};
      for (let id in this.notesStore)
        if (
          this.notesStore[id]?.trim() &&
          (this.notesSearch === "" ||
            this.notesStore[id]
              .toLowerCase()
              .includes(this.notesSearch.toLowerCase()))
        )
          f[id] = this.notesStore[id];
      return f;
    },
    getRecordNameById(id) {
      let r = this.allItems.find((i) => i.id === id);
      return r ? r.name : id;
    },
    getRecordCategoryById(id) {
      let r = this.allItems.find((i) => i.id === id);
      return r ? r.category : "";
    },
    openDossierById(id) {
      let found = this.allItems.find((i) => i.id === id);
      if (found) this.selectedRecord = found;
    },
    openDossierByName(name) {
      let found = this.allItems.find(
        (i) => i.name.toLowerCase() === name.toLowerCase() || i.id === name,
      );
      if (found) this.selectedRecord = found;
      else alert(`No matching record found for "${name}"`);
    },
    deleteNote(id) {
      delete this.notesStore[id];
      this.saveLocal();
    },
    exportAllNotes() {
      let data = JSON.stringify(this.notesStore, null, 2);
      let blob = new Blob([data], {
        type: "application/json",
      });
      let a = document.createElement("a");
      a.href = URL.createObjectURL(blob);
      a.download = "black_archive_notes.json";
      a.click();
    },
    async shareApp() {
      try {
        if (navigator.share)
          await navigator.share({
            title: "The Black Archive",
            text: "Open research library",
            url: window.location.href,
          });
        else if (navigator.clipboard) {
          await navigator.clipboard.writeText(window.location.href);
          alert("Link copied.");
        } else alert("Copy URL manually.");
      } catch (e) {}
    },
    init() {
      this.buildFullDataset();
      this.loadLocal();
    },
    buildFullDataset() {
      this.allItems = generateFullArchive();
    },
    get filteredItems() {
      let items = [...this.allItems];
      if (
        this.activeCategory !== "All" &&
        this.activeCategory !== "Favorites" &&
        this.activeCategory !== "NotesPage"
      )
        items = items.filter((i) => i.category === this.activeCategory);
      if (this.activeCategory === "Favorites")
        items = items.filter((i) => this.favoritesIds.has(i.id));
      if (this.searchTerm.trim()) {
        let t = this.searchTerm.toLowerCase();
        items = items.filter((i) =>
          JSON.stringify(i).toLowerCase().includes(t),
        );
      }
      return items;
    },
    get humanTimelineFiltered() {
      let h = this.allItems.filter((i) => i.category === "Human Timeline");
      if (this.currentHumanEra !== "All")
        h = h.filter(
          (i) =>
            (i.era || "")
              .toLowerCase()
              .includes(this.currentHumanEra.toLowerCase()) ||
            (i.dateRange || "")
              .toLowerCase()
              .includes(this.currentHumanEra.toLowerCase()),
        );
      return h;
    },
    getCountForCategory(cat) {
      if (cat === "All") return this.allItems.length;
      if (cat === "Favorites") return this.favoritesIds.size;
      if (cat === "NotesPage")
        return Object.values(this.notesStore).filter((n) => n?.trim()).length;
      return this.allItems.filter((i) => i.category === cat).length;
    },
    openDossier(r) {
      this.selectedRecord = r;
    },
    toggleFavorite(id) {
      if (this.favoritesIds.has(id)) this.favoritesIds.delete(id);
      else this.favoritesIds.add(id);
      this.saveLocal();
    },
    saveLocal() {
      localStorage.setItem("bfav", JSON.stringify([...this.favoritesIds]));
      localStorage.setItem("bnotes", JSON.stringify(this.notesStore));
    },
    loadLocal() {
      let f = localStorage.getItem("bfav");
      if (f) this.favoritesIds = new Set(JSON.parse(f));
      let n = localStorage.getItem("bnotes");
      if (n) this.notesStore = JSON.parse(n);
      else this.notesStore = {};
    },
    randomDossier() {
      if (this.allItems.length)
        this.selectedRecord =
          this.allItems[Math.floor(Math.random() * this.allItems.length)];
    },
    hasAnyConnections() {
      return (
        this.selectedRecord &&
        (this.selectedRecord.associatedWitnessesList?.length ||
          this.selectedRecord.associatedCases?.length ||
          this.selectedRecord.associatedLocations?.length ||
          this.selectedRecord.associatedTechnologies?.length)
      );
    },
    hasSources() {
      return (
        this.selectedRecord &&
        ((this.selectedRecord.sources &&
          typeof this.selectedRecord.sources === "string") ||
          (this.selectedRecord.sourcesArray &&
            this.selectedRecord.sourcesArray.length))
      );
    },
    shouldShowField(key, val) {
      const exclude = [
        "id",
        "image",
        "icon",
        "shortDesc",
        "fullDescription",
        "tags",
        "sources",
        "sourcesArray",
        "relatedEntries",
        "name",
        "category",
        "claimClassification",
        "description",
        "kardashev",
        "civilizationType",
        "associatedLocations",
        "associatedTechnologies",
        "associatedWitnessesList",
        "associatedCases",
        "origin",
        "timeline",
        "geography",
        "societalStructure",
        "technologyLevel",
        "economy",
        "religionSpirituality",
        "collapseTheory",
        "associatedArtifacts",
        "aliases",
        "appearance",
        "governance",
        "controversyNotes",
        "skepticismNotes",
        "modernRelevance",
      ];
      return (
        !exclude.includes(key) &&
        val &&
        val !== "" &&
        !(Array.isArray(val) && val.length === 0)
      );
    },
    formatFieldKey(k) {
      return k
        .replace(/([A-Z])/g, " $1")
        .replace(/^./, (str) => str.toUpperCase());
    },
    formatFieldValue(key, val, record) {
      if (Array.isArray(val)) return val.join(", ");
      if (typeof val === "object") return JSON.stringify(val);
      return val;
    },
    copySummaryToClipboard(record) {
      let summary = `📜 DOSSIER: ${record.name}\nCategory: ${record.category}\nKardashev: ${this.formatKardashev(record.kardashev)}\nSummary: ${record.fullDescription || record.shortDesc}`;
      navigator.clipboard.writeText(summary);
      alert("Summary copied.");
    },
    formatKardashev(k) {
      const map = {
        0: "Type 0",
        1: "Type I",
        2: "Type II",
        3: "Type III",
        spec12: "Speculative Type I-II",
        hypo2: "Hypothetical Type II",
      };
      return map[k] || k || "Unspecified";
    },
    getKardashevColorClass(k) {
      const map = {
        0: "k-type0",
        1: "k-type1",
        2: "k-type2",
        3: "k-type3",
        spec12: "k-speculative",
        hypo2: "k-hypothetical",
      };
      return map[k] || "bg-gray-700";
    },
    getActiveCategoryIcon() {
      const found = this.categories.find(
        (cat) => cat.id === this.activeCategory,
      );
      return found ? found.icon : "fas fa-book-open";
    },
  };
}

